# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.widget.Toast

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        val intent = intent
        if (Intent.ACTION_SEND == intent.action) {
            handleSend(intent)
        } else if (Intent.ACTION_SEND_MULTIPLE == intent.action) {
            handleSendMultiple(intent)
        }
    }

    private fun handleSend(intent: Intent) {
        when {
            intent.type?.startsWith("image/") == true -> {
                val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                processImage(imageUri)
            }
            "text/plain" == intent.type -> {
                val sharedText: String? = intent.getStringExtra(Intent.EXTRA_TEXT)
                processUrl(sharedText)
            }
        }
    }

    private fun handleSendMultiple(intent: Intent) {
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris ->
            for (uri in imageUris) {
                if (uri.toString().startsWith("content://")) {
                    processImage(uri)
                } else {
                    Toast.makeText(this, "Unsupported file type", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    private fun processImage(imageUri: Uri?) {
        // Implement your image processing logic here
        Toast.makeText(this, "Processing image: $imageUri", Toast.LENGTH_SHORT).show()
    }

    private fun processUrl(url: String?) {
        // Implement your URL processing logic here
        Toast.makeText(this, "Processing URL: $url", Toast.LENGTH_SHORT).show()
    }
}